// ==================== 类型定义 ====================
interface TextModel {
  name: string;
  modelName: string;
  type: "text";
  think: boolean;
}

interface ImageModel {
  name: string;
  modelName: string;
  type: "image";
  mode: ("text" | "singleImage" | "multiReference")[];
}

interface VideoModel {
  name: string;
  modelName: string;
  type: "video";
  mode: ("singleImage" | "startEndRequired" | "endFrameOptional" | "startFrameOptional" | "text")[];
  audio: "optional" | false | true;
  durationResolutionMap: { duration: number[]; resolution: string[] }[];
}

interface VendorConfig {
  id: string;
  author: string;
  description?: string;
  name: string;
  icon?: string;
  inputs: {
    key: string;
    label: string;
    type: "text" | "password" | "url";
    required: boolean;
    placeholder?: string;
  }[];
  inputValues: Record<string, string>;
  models: (TextModel | ImageModel | VideoModel)[];
}

// ==================== 全局工具函数 ====================
declare const zipImage: (completeBase64: string, size: number) => Promise<string>;
declare const zipImageResolution: (completeBase64: string, targetResolution: string) => Promise<string>;
declare const fetch: (url: string, options?: any) => Promise<any>;
declare const FormData: any;
declare const Blob: any;

// ==================== 供应商数据 ====================
const TOONFLOW_API_URL = "https://api.toonflow.net/v1";

class Vendor {
  private config: VendorConfig;
  private baseUrl: string;
  private apiKey: string;

  constructor(config: VendorConfig) {
    this.config = config;
    this.baseUrl = config.inputValues?.baseUrl || TOONFLOW_API_URL;
    this.apiKey = config.inputValues?.apiKey || "";
  }

  // 文本生成
  async textRequest(model: TextModel) {
    return async (params: { messages: any[]; temperature?: number; maxTokens?: number }) => {
      const response = await fetch(`${this.baseUrl}/chat/completions`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${this.apiKey}`,
        },
        body: JSON.stringify({
          model: model.modelName,
          messages: params.messages,
          temperature: params.temperature ?? 0.7,
          max_tokens: params.maxTokens ?? 2048,
        }),
      });
      const data = await response.json();
      return data.choices?.[0]?.message?.content || "";
    };
  }

  // 图片生成
  async imageRequest(model: ImageModel) {
    return async (input: { prompt: string; imageBase64?: string[]; size?: string }) => {
      const formData = new FormData();
      formData.append("model", model.modelName);
      formData.append("prompt", input.prompt);

      if (input.imageBase64 && input.imageBase64.length > 0) {
        for (let i = 0; i < input.imageBase64.length; i++) {
          const base64 = input.imageBase64[i];
          if (base64) {
            const compressed = await zipImage(base64, 5 * 1024 * 1024);
            const blob = new Blob([Buffer.from(compressed, "base64")], { type: "image/jpeg" });
            formData.append(`image`, blob, `image_${i}.jpg`);
          }
        }
      }

      const response = await fetch(`${this.baseUrl}/images/generations`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${this.apiKey}`,
        },
        body: formData,
      });
      const data = await response.json();
      return data.url || data.data?.[0]?.url || "";
    };
  }

  // 视频生成
  async videoRequest(model: VideoModel) {
    return async (input: {
      prompt: string;
      firstImageBase64?: string;
      lastImageBase64?: string;
      duration?: number;
      resolution?: string;
      aspectRatio?: string;
      generateAudio?: boolean;
    }) => {
      const formData = new FormData();
      formData.append("model", model.modelName);
      formData.append("prompt", input.prompt);

      if (input.duration) {
        formData.append("duration", String(input.duration));
      }
      if (input.resolution) {
        formData.append("resolution", input.resolution);
      }
      if (input.aspectRatio) {
        formData.append("aspect_ratio", input.aspectRatio);
      }
      if (input.generateAudio !== undefined) {
        formData.append("generate_audio", String(input.generateAudio));
      }

      // 处理首帧
      if (input.firstImageBase64) {
        const compressed = await zipImage(input.firstImageBase64, 5 * 1024 * 1024);
        const blob = new Blob([Buffer.from(compressed, "base64")], { type: "image/jpeg" });
        formData.append("first_frame", blob, "first_frame.jpg");
      }

      // 处理尾帧
      if (input.lastImageBase64) {
        const compressed = await zipImage(input.lastImageBase64, 5 * 1024 * 1024);
        const blob = new Blob([Buffer.from(compressed, "base64")], { type: "image/jpeg" });
        formData.append("last_frame", blob, "last_frame.jpg");
      }

      const response = await fetch(`${this.baseUrl}/videos/generations`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${this.apiKey}`,
        },
        body: formData,
      });
      const data = await response.json();
      return data.task_id || data.id || "";
    };
  }

  // TTS生成
  async ttsRequest(model: any) {
    return async (input: { text: string; voiceId?: string; speed?: number; emotion?: string }) => {
      const response = await fetch(`${this.baseUrl}/audio/speech`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${this.apiKey}`,
        },
        body: JSON.stringify({
          model: model.modelName,
          input: input.text,
          voice: input.voiceId || "default",
          speed: input.speed || 1.0,
          emotion: input.emotion || "neutral",
        }),
      });
      const data = await response.json();
      return data.url || data.audio_url || "";
    };
  }
}

module.exports = { Vendor };

